import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import './index.css';

// Layout
import Layout from './components/Layout';

// Pages
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import DashboardPage from './pages/DashboardPage';
import EquipmentPage from './pages/EquipmentPage';
import RentalsPage from './pages/RentalsPage';
import RequestsPage from './pages/RequestsPage';
import MaintenancePage from './pages/MaintenancePage';
import UsersPage from './pages/UsersPage';
import ReportsPage from './pages/ReportsPage';
import CicdPage from './pages/CicdPage';
import MonitoringPage from './pages/MonitoringPage';
import NotFoundPage from './pages/NotFoundPage';

// Protected Route wrapper
const ProtectedRoute = ({ children, roles }) => {
  const { user, loading } = useAuth();
  if (loading) return <div className="loading-wrapper"><div className="spinner" /></div>;
  if (!user) return <Navigate to="/login" replace />;
  if (roles && !roles.includes(user.role)) {
    return (
      <div className="access-denied slide-up">
        <div className="icon">🔒</div>
        <h2>ACCESS RESTRICTED</h2>
        <p>Your role <strong>{user.role}</strong> does not have permission to view this page.</p>
      </div>
    );
  }
  return children;
};

const PublicRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return <div className="loading-wrapper"><div className="spinner" /></div>;
  if (user) return <Navigate to="/" replace />;
  return children;
};

function AppRoutes() {
  return (
    <Routes>
      {/* Public */}
      <Route path="/login" element={<PublicRoute><LoginPage /></PublicRoute>} />
      <Route path="/register" element={<PublicRoute><RegisterPage /></PublicRoute>} />

      {/* Protected — all roles */}
      <Route path="/" element={<ProtectedRoute><Layout /></ProtectedRoute>}>
        <Route index element={<DashboardPage />} />
        <Route path="equipment" element={<EquipmentPage />} />
        <Route path="rentals" element={<RentalsPage />} />
        <Route path="requests" element={<RequestsPage />} />

        {/* Manager + Admin + Technician */}
        <Route path="maintenance" element={
          <ProtectedRoute roles={['admin','manager','technician']}>
            <MaintenancePage />
          </ProtectedRoute>
        } />

        {/* Admin + Manager */}
        <Route path="reports" element={
          <ProtectedRoute roles={['admin','manager']}>
            <ReportsPage />
          </ProtectedRoute>
        } />
        <Route path="cicd" element={
          <ProtectedRoute roles={['admin','manager']}>
            <CicdPage />
          </ProtectedRoute>
        } />
        <Route path="monitoring" element={
          <ProtectedRoute roles={['admin','manager','technician']}>
            <MonitoringPage />
          </ProtectedRoute>
        } />

        {/* Admin only */}
        <Route path="users" element={
          <ProtectedRoute roles={['admin']}>
            <UsersPage />
          </ProtectedRoute>
        } />
      </Route>

      <Route path="*" element={<NotFoundPage />} />
    </Routes>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <AppRoutes />
      </AuthProvider>
    </BrowserRouter>
  );
}
